const text = $input.item.json.text || '';
const trig = $('PDF Import Trigger').item.json.body;
return [{
  json: {
    draft_id: trig.draft_id,
    file_name: trig.file_name,
    pdf_text: text,
    anthropic_body: JSON.stringify({
      model: "claude-haiku-4-5-20251001",
      max_tokens: 300,
      system: "זהה את סוג טופס כיבוי האש. החזר JSON בלבד: {form_type:<1-7 או null>,confidence:<0-1>,reason:<string>}\n\nטפסים:\n1=עמדות כיבוי/גלגלונים/זרנוקים\n2=מטפים מיטלטלים\n3=משאבות\n4=גילוי אש\n5=כיבוי בלוחות חשמל\n6=כריזת חירום\n7=ספרינקלרים/מתזים",
      messages: [{role:"user",content:"טקסט מהטופס (500 תווים ראשונים):\n"+text.substring(0,500)}]
    })
  }
}];

const raw = ($input.item.json.content || [])[0]?.text || '{}';
let cls = {form_type: null, confidence: 0};
try {
  const m = raw.match(/\{[\s\S]*?\}/);
  cls = JSON.parse(m ? m[0] : '{}');
} catch(e) {}

const prev = $('Build Classify Body').item.json;

const sysPrompt = "חלץ שדות מטופס כיבוי אש ישראלי. החזר JSON בלבד (ללא טקסט אחר):\n" +
"{\n" +
"  \"common\": {\n" +
"    \"business_name\": null,\n" +
"    \"business_type\": null,\n" +
"    \"business_number\": null,\n" +
"    \"address_street\": null,\n" +
"    \"address_house_number\": null,\n" +
"    \"address_city\": null,\n" +
"    \"address_zip\": null,\n" +
"    \"contact_name\": null,\n" +
"    \"contact_role\": null,\n" +
"    \"contact_phone\": null,\n" +
"    \"contact_email\": null,\n" +
"    \"inspection_date_day\": null,\n" +
"    \"inspection_date_month\": null,\n" +
"    \"inspection_date_year\": null,\n" +
"    \"inspector_id\": null\n" +
"  },\n" +
"  \"rows\": [],\n" +
"  \"confidence_scores\": {\n" +
"    \"business_name\": 0.0, \"business_type\": 0.0, \"business_number\": 0.0,\n" +
"    \"address_street\": 0.0, \"address_city\": 0.0,\n" +
"    \"contact_name\": 0.0, \"contact_phone\": 0.0,\n" +
"    \"inspection_date_day\": 0.0, \"inspection_date_month\": 0.0, \"inspection_date_year\": 0.0\n" +
"  }\n" +
"}";

return [{
  json: {
    draft_id: prev.draft_id,
    pdf_text: prev.pdf_text,
    form_type: cls.form_type,
    classification_confidence: cls.confidence || 0,
    anthropic_body: JSON.stringify({
      model: "claude-haiku-4-5-20251001",
      max_tokens: 2048,
      system: sysPrompt,
      messages: [{
        role: "user",
        content: "סוג טופס: " + (cls.form_type || "לא ידוע") + "\nטקסט:\n" + prev.pdf_text.substring(0, 3500)
      }]
    })
  }
}];

const raw = ($input.item.json.content || [])[0]?.text || '{}';
let extracted = {common:{}, rows:[], confidence_scores:{}};
try {
  const m = raw.match(/\{[\s\S]*\}/);
  extracted = JSON.parse(m ? m[0] : '{}');
} catch(e) {}

const prev = $('Parse Classify + Build Extract').item.json;

return [{
  json: {
    draft_id: prev.draft_id,
    form_type: prev.form_type,
    classification_confidence: prev.classification_confidence,
    pdf_text: prev.pdf_text,
    extracted_data: JSON.stringify({
      common: extracted.common || {},
      rows: extracted.rows || []
    }),
    confidence_scores: JSON.stringify(extracted.confidence_scores || {}),
    business_name_search: ((extracted.common || {}).business_name || '').trim().toLowerCase(),
  }
}];

const prev = $('Parse Extraction').item.json;
const customersRaw = $input.item.json;

const customers = Array.isArray(customersRaw)
  ? customersRaw
  : Array.isArray(customersRaw?.data) ? customersRaw.data : [];

const searchName = prev.business_name_search || '';
let matchedId = null, matchedName = null, matchScore = 0;

if (searchName && customers.length) {
  for (const c of customers) {
    const cName = (c.name || c.business_name || '').trim().toLowerCase();
    if (!cName) continue;
    const longer = Math.max(searchName.length, cName.length);
    if (!longer) continue;
    const shorter = Math.min(searchName.length, cName.length);
    let charMatches = 0;
    for (let i = 0; i < shorter; i++) {
      if (searchName[i] === cName[i]) charMatches++;
    }
    const includeBonus = (cName.includes(searchName) || searchName.includes(cName)) ? 0.35 : 0;
    const score = (charMatches / longer) + includeBonus;
    if (score > matchScore && score > 0.4) {
      matchScore = score;
      matchedId = c.id;
      matchedName = c.name || c.business_name;
    }
  }
}

const payload = {
  status: 'ready_for_review',
  detected_form_type: String(prev.form_type || 'unknown'),
  classification_confidence: prev.classification_confidence || 0,
  extracted_data: prev.extracted_data,
  confidence_scores: prev.confidence_scores,
  import_raw_text: (prev.pdf_text || '').substring(0, 4000),
  auto_match_confidence: matchScore,
};
if (matchedId) payload.customer_id = matchedId;
if (matchedName) payload.customer_name = matchedName;

return [{
  json: {
    draft_id: prev.draft_id,
    payload: payload
  }
}];
